firmware_template.source:
#include "blynk_iot.h"
#define BLYNK_PRINT Serial
#include <WiFi.h>
#include <BlynkSimpleEsp32.h>
void blynk_setup(const char*auth,const char*ssid,const char*pass){Blynk.begin(auth,ssid,pass);Serial.println("[blynk] OK");}
void blynk_loop(){Blynk.run();}
void blynk_write_float(int p,float v){Blynk.virtualWrite(p,v);}
void blynk_write_string(int p,const char*v){Blynk.virtualWrite(p,v);}
